def fibonacci(n):
    if n <= 0:
        print("Nhập số nguyên dương!")
    elif n == 1:
        return 0
    elif n == 2:
        return 1
    else:
        a, b = 0, 1
        for i in range(2, n):
            a, b = b, a + b
        return b

print(fibonacci(9)) # Output: 34
print(fibonacci(11))

