Viết đoạn code Python tính số Fibonacci thứ n.

# Response:
def fibonacci(n):
    if n < 0:
        print("Input is not a positive integer.")
    elif n == 0:
        return 0
    elif n == 1:
        return 1
    else:
        return fibonacci(n-1) + fibonacci(n-2)
